#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    Node* next;
    Node(int x) { data = x; next = nullptr; }
};

Node* buildNodeList(vector<int>& vals) {
    Node dummy(0);
    Node* tail = &dummy;
    for (int v : vals) {
        tail->next = new Node(v);
        tail = tail->next;
    }
    return dummy.next;
}

void printNodeList(Node* head) {
    while (head) {
        cout << head->data;
        if (head->next) cout << " ";
        head = head->next;
    }
}

