Copy List with Random Pointer.cpp.wrapper_main:
#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    int val;
    Node* next;
    Node* random;
    Node(int _val) { val = _val; next = nullptr; random = nullptr; }
};

Node* buildNodeListRandom(vector<pair<int,int>>& vals) {
    int n = vals.size();
    if (n == 0) return nullptr;
    vector<Node*> nodes(n);
    for (int i = 0; i < n; i++) nodes[i] = new Node(vals[i].first);
    for (int i = 0; i < n; i++) {
        if (i + 1 < n) nodes[i]->next = nodes[i + 1];
        int r = vals[i].second;
        nodes[i]->random = (r == -1) ? nullptr : nodes[r];
    }
    return nodes[0];
}

void printNodeList(Node* head) {
    while (head) {
        cout << head->val;
        if (head->next) cout << " ";
        head = head->next;
    }
}

int main() {
    int head_n; cin >> head_n;
    vector<pair<int,int>> head_vals(head_n);
    for (int i = 0; i < head_n; i++) cin >> head_vals[i].first >> head_vals[i].second;
    Node* head = buildNodeListRandom(head_vals);

    Solution obj;
    auto ans = obj.copyRandomList(head);
    printNodeList(ans);
}

