using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode() : val(0), next(nullptr) {}
    ListNode(int x) : val(x), next(nullptr) {}
    ListNode(int x, ListNode *next) : val(x), next(next) {}
};

ListNode* buildList(vector<int>& vals) {
    ListNode dummy(0);
    ListNode* tail = &dummy;
    for (int v : vals) {
        tail->next = new ListNode(v);
        tail = tail->next;
    }
    return dummy.next;
}

void printList(ListNode* head) {
    while (head) {
        cout << head->val;
        if (head->next) cout << " ";
        head = head->next;
    }
}

int main() {
    int head_n; cin >> head_n;
    vector<int> head_vals(head_n);
    for (int i = 0; i < head_n; i++) cin >> head_vals[i];
    ListNode* head = buildList(head_vals);
    int k;
    cin >> k;

    Solution obj;
    auto ans = obj.reverseKGroup(head, k);
    printList(ans);
}

