#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode() : val(0), left(nullptr), right(nullptr) {}
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
};

TreeNode* buildTree(vector<string>& toks) {
    if (toks.empty() || toks[0] == "null") return nullptr;
    TreeNode* root = new TreeNode(stoi(toks[0]));
    queue<TreeNode*> q;
    q.push(root);
    size_t i = 1;
    while (!q.empty() && i < toks.size()) {
        TreeNode* cur = q.front(); q.pop();
        if (i < toks.size()) {
            if (toks[i] != "null") {
                cur->left = new TreeNode(stoi(toks[i]));
                q.push(cur->left);
            }
            i++;
        }
        if (i < toks.size()) {
            if (toks[i] != "null") {
                cur->right = new TreeNode(stoi(toks[i]));
                q.push(cur->right);
            }
            i++;
        }
    }
    return root;
}

void printTree(TreeNode* root) {
    if (!root) return;
    queue<TreeNode*> q;
    q.push(root);
    vector<string> out;
    while (!q.empty()) {
        TreeNode* cur = q.front(); q.pop();
        if (!cur) { out.push_back("null"); continue; }
        out.push_back(to_string(cur->val));
        q.push(cur->left);
        q.push(cur->right);
    }
    while (!out.empty() && out.back() == "null") out.pop_back();
    for (size_t i = 0; i < out.size(); i++) cout << out[i] << (i + 1 < out.size() ? " " : "");
}

