    int root_n; cin >> root_n;
    vector<string> root_toks(root_n);
    for (int i = 0; i < root_n; i++) cin >> root_toks[i];
    TreeNode* root = buildTree(root_toks);

    Solution obj;
    auto ans = obj.increasingBST(root);
    printTree(ans);
}

