N-ary Tree Postorder Traversal.cpp.wrapper_main:
#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    int val;
    vector<Node*> children;
    Node() {}
    Node(int _val) { val = _val; }
    Node(int _val, vector<Node*> _children) { val = _val; children = _children; }
};

Node* buildNaryTree(vector<string>& toks) {
    // Level-order with "#" separating each node's children group.
    // Format: [val1, #, val2, val3, #, #, ...] (LeetCode N-ary serialization)
    if (toks.empty()) return nullptr;
    size_t idx = 0;
    Node* root = new Node(stoi(toks[idx++]));
    queue<Node*> q;
    q.push(root);
    while (!q.empty() && idx < toks.size()) {
        Node* cur = q.front(); q.pop();
        while (idx < toks.size() && toks[idx] != "#") {
            Node* child = new Node(stoi(toks[idx++]));
            cur->children.push_back(child);
            q.push(child);
        }
        if (idx < toks.size()) idx++; // skip '#'
    }
    return root;
}

void printNaryTree(Node* root) {
    vector<int> out;
    // simple preorder print of values (children counts not encoded back)
    function<void(Node*)> dfs = [&](Node* node) {
        if (!node) return;
        out.push_back(node->val);
        for (auto c : node->children) dfs(c);
    };
    dfs(root);
    for (size_t i = 0; i < out.size(); i++) cout << out[i] << (i + 1 < out.size() ? " " : "");
}

int main() {
    int root_n; cin >> root_n;
    vector<string> root_toks(root_n);
    for (int i = 0; i < root_n; i++) cin >> root_toks[i];
    Node* root = buildNaryTree(root_toks);

    Solution obj;
    auto ans = obj.postorder(root);
    for (size_t i = 0; i < ans.size(); i++) cout << ans[i] << " ";
}

