    while (!q.empty() && i < toks.size()) {
        Node* cur = q.front(); q.pop();
        if (i < toks.size()) {
            if (toks[i] != "null") {
                cur->left = new Node(stoi(toks[i]));
                q.push(cur->left);
            }
            i++;
        }
        if (i < toks.size()) {
